// dans un fichier shared/amende.js
export function calculAmende(joursRetard) {
  if(joursRetard <= 0) return 0;
  let tarif = 50;
  if(joursRetard > 30) tarif = 100;
  else if(joursRetard > 7) tarif = 75;
  return joursRetard * tarif;
}

// dans chaque fichier : import { calculAmende } from './shared/amende.js';
// puis l'utiliser normalement.
Bénéfices : modification centralisée, réduction de duplication, meilleure lisibilité.

function isPrime($n) {
  if($n <= 1) return false;
  for($i=2; $i <= sqrt($n); $i++) {
    if($n % $i == 0) return false;
  }
  return true;
}

Améliorations : suppression de la variable flag inutile (simplification logique), arrêt à sqrt($n) au lieu de $n (gain de performance), retour immédiat dès qu’un diviseur est trouvé. Le code est plus concis et exprime directement l'intention.
